const item = $input.first().json;
const raw = item.text ?? item.output ?? item.response ?? '';
let intent = 'conversation';
let reply = 'Hello! I am Syncra Society assistant. How can I help you today?';

try {
  const cleaned = String(raw).replace(/```json|```/gi, '').trim();
  const parsed = JSON.parse(cleaned);
  if (parsed.intent) intent = String(parsed.intent).toLowerCase();
  if (parsed.reply) reply = String(parsed.reply).trim();
} catch {
  const lower = String(raw).toLowerCase();
  if (/complaint|ticket|maintenance|broken|leak|helpdesk|repair|not working|issue/.test(lower)) {
    intent = 'ticket';
  } else if (String(raw).trim()) {
    reply = String(raw).trim().slice(0, 500);
  }
}

if (['ticket', 'complaint', 'payment_receipt'].includes(intent)) intent = 'ticket';
else intent = 'conversation';

return [{ json: { ...item, groqIntent: intent, groqReply: reply } }];

const item = $input.first().json;
const phone = String(item.phone ?? 'whatsapp-unknown').trim();
const flatNumber = item.flatNumber ? String(item.flatNumber).trim() : null;
return [{ json: { ...item, portalPayload: { societyId: item.societyId, flatNumber, phone, messageType: 'ticket', subject: item.subject?.trim() || (flatNumber ? `WhatsApp helpdesk — Flat ${flatNumber}` : 'WhatsApp helpdesk ticket'), description: String(item.description ?? '').trim(), amount: item.amount ?? null } } }];

const item = $input.first().json;
let msg = String(item.groqReply ?? 'Hello! How can I help you today?').trim();
while (msg.startsWith('==')) msg = msg.slice(2).trim();
while (msg.startsWith('=')) msg = msg.slice(1).trim();
return [{ json: { rawMessage: msg } }];

function sanitizeText(raw) {
  let msg = String(raw ?? '').trim();
  while (msg.startsWith('==')) msg = msg.slice(2).trim();
  while (msg.startsWith('=')) msg = msg.slice(1).trim();
  msg = msg.replace(/==+/g, '');
  return msg.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const item = $input.first();
const fromHttp = item.body ?? item.json?.body;
let twiml = String(fromHttp ?? item.json?.rawMessage ?? item.json?.twiml ?? '').trim();

if (twiml.includes('<Response>')) {
  twiml = twiml.replace(/==+/g, '');
  const match = twiml.match(/<Message>([\s\S]*?)<\/Message>/i);
  if (match) {
    const inner = sanitizeText(match[1]);
    twiml = `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${inner}</Message></Response>`;
  }
} else {
  const inner = sanitizeText(twiml);
  twiml = `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${inner}</Message></Response>`;
}

return [{ json: { twiml } }];
